sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading || newValue === '') return;

    var start = g_form.getValue('start_date');
    var end = g_form.getValue('end_date');

    if (start && end) {
        var s = new GlideDate();
        s.setValue(start);
        var e = new GlideDate();
        e.setValue(end);

        var count = 0;
        var cur = new GlideDate();
        cur.setValue(start);

        while (cur.compareTo(e) <= 0) {
            var dow = cur.getDayOfWeekUTC();
            if (dow !== 1 && dow !== 7) count++;
            cur.addDaysUTC(1);
        }
        g_form.setValue('total_days', count);
    }
}
